/**
 * event
 * @name f_downExcelSheet
 * @description 엑셀다운로드
 */
scwin.f_downExcelSheet = async function () {
  if (ds_masterblList.getRowCount()) {
    let cfrm = await $c.win.confirm($p, "Master B/L List를 EXCEL로 다운로드 받으시겠습니까?");
    if (cfrm) {
      $c.data.downloadGridViewExcel($p, gr_masterblList, {
        fileName: "Master BL List.xlsx",
        sheetName: "Master BL List"
      });
    }
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002);
  }
};

/**
 * event
 * @name f_dateLoading
 * @description hhio에따른 date default
 */
scwin.f_dateLoading = function () {
  if (cnd_rd_mhio.getValue() == "O") {
    cnd_ed_mhetdFrom.setValue(scwin.strPreDate);
    cnd_ed_mhetdTo.setValue(scwin.strCurDate);
    cnd_ed_mhetaFrom.setValue("");
    cnd_ed_mhetaTo.setValue("");
  } else {
    cnd_ed_mhetdFrom.setValue("");
    cnd_ed_mhetdTo.setValue("");
    cnd_ed_mhetaFrom.setValue(scwin.strPreDate);
    cnd_ed_mhetaTo.setValue(scwin.strCurDate);
  }
};

/**
 * event
 * @name f_Tracking
 * @description 선사 트래킹
 */
scwin.f_Tracking = async function () {
  //구현 불가능한 기능, 버튼 안보이도록 처리해서 막음
  return;
  if (!ds_masterblList.getRowCount()) {
    await $c.win.alert($p, "선사 Tracking 할 Master B/L을 조회해 주세요.");
    return;
  }
  let row = gr_masterblList.getFocusedRowIndex();
  dma_retrieveCode.setJSON({
    "grpCd": "IL052",
    "cd": ds_masterblList.getCellData(row, "mhlinercd")
  });
  await $c.sbm.execute($p, sbm_retrieveCodeCMD);
  let vline = "";
  if (ds_liner.getRowCount() > 0 && ds_liner.getCellData(0, "cdNm") != "") {
    vline = ds_liner.getCellData(0, "cdNm");
  }
  let vparm = ds_masterblList.getCellData(row, "mhmblno");
  let objWSH = new ActiveXObject("WScript.Shell");
  let retval = objWSH.Run("C:\dbexp_scrap1\\upgrade.exe job=blsearch" + "&linecode=" + vline + "&no=" + vparm + "&", 1, true);
};

