/**
 * event
 * @name sbm_retrieve_submitdone
 * @description
 */
scwin.sbm_retrieve_submitdone = async function (e) {
  let rowCnt = ds_masterblList.getRowCount();
  totalRows_item.setValue(rowCnt); // 조회된 건수를 매출입항목Grid 하단에 표시한다.
  if (ds_masterblList.getRowCount()) {
    scwin.f_set("RETRIEVE");
    gr_masterblList.setFocusedCell(0, gr_masterblList.getFocusedColumnIndex() ?? 0, false);
  } else {
    await $c.gus.cfAlertMsg($p, E_MSG_CM_WRN_002);
  }
};

